import { useState, useMemo, useRef, useLayoutEffect } from 'react';
import { DataGrid, type Column, SelectColumn } from 'react-data-grid';
import { useQuery } from '@tanstack/react-query';
import 'react-data-grid/lib/styles.css';
import api from '@/api/app/client';
import type { Pagination } from '@/types/api';
import { queryKeys } from '@/lib/queryKeys';

// eslint-disable-next-line @typescript-eslint/no-explicit-any
type GridRow = Record<string, any>;

interface UniversalSheetProps {
  endpoint?: string;
  data?: GridRow[];
  title: string;
  enableSelection?: boolean;
  selectedRows?: Set<string | number>;
  onSelectedRowsChange?: (rows: Set<string | number>) => void;
  /** Rows whose checkboxes are locked — cannot be toggled by the user. */
  disabledRows?: Set<string | number>;
  customColumns?: Column<GridRow>[];
  pageSize?: number;
}

export default function SheetGrid({
  endpoint,
  data: directData,
  title,
  enableSelection = false,
  selectedRows,
  onSelectedRowsChange,
  disabledRows,
  customColumns,
  pageSize: initialPageSize = 10
}: UniversalSheetProps) {
  const [page, setPage] = useState(1);
  const [pageSize] = useState(initialPageSize);
  const [searchQuery, setSearchQuery] = useState('');

  const { data: rawResponse, isLoading } = useQuery({
    queryKey: queryKeys.gridData(endpoint ?? '', page, pageSize),
    enabled: !!endpoint,
    queryFn: async () => {
      const res = await api.get<Pagination<GridRow>>(endpoint!, {
        params: { pageIndex: page, pageSize: pageSize }
      });
      return res.data;
    }
  });

  const { rows } = useMemo(() => {
    const rawRows = directData ?? rawResponse?.data ?? [];
    const formattedRows: GridRow[] = rawRows.map((item, i) => ({
      ...item,
      id: item.id ?? item._id ?? i,
    }));
    const info = {
      totalCount: endpoint ? (rawResponse?.totalCount ?? 0) : formattedRows.length,
      totalPages: endpoint ? (rawResponse?.totalPages ?? 1) : 1,
      hasNextPage: endpoint ? (rawResponse?.hasNextPage ?? false) : false,
      hasPreviousPage: endpoint ? (rawResponse?.hasPreviousPage ?? false) : false,
    };
    return { rows: formattedRows, paginationInfo: info };
  }, [rawResponse, directData, endpoint]);

  const paginationInfo = useMemo(() => ({
    totalCount: endpoint ? (rawResponse?.totalCount ?? 0) : rows.length,
    totalPages: endpoint ? (rawResponse?.totalPages ?? 1) : 1,
    hasNextPage: endpoint ? (rawResponse?.hasNextPage ?? false) : false,
    hasPreviousPage: endpoint ? (rawResponse?.hasPreviousPage ?? false) : false,
  }), [rawResponse, rows, endpoint]);

  const filteredRows = useMemo(() =>
    rows.filter(row =>
      Object.values(row).some(v =>
        String(v).toLowerCase().includes(searchQuery.toLowerCase())
      )
    ), [rows, searchQuery]);

  // Refs keep custom column render closures current without adding them to useMemo deps.
  const selectedRowsRef = useRef(selectedRows);
  const onSelectedRowsChangeRef = useRef(onSelectedRowsChange);
  const filteredRowsRef = useRef(filteredRows);
  const disabledRowsRef = useRef(disabledRows);
  useLayoutEffect(() => {
    selectedRowsRef.current = selectedRows;
    onSelectedRowsChangeRef.current = onSelectedRowsChange;
    filteredRowsRef.current = filteredRows;
    disabledRowsRef.current = disabledRows;
  });

  const columns: Column<GridRow>[] = useMemo(() => {
    const baseCols: Column<GridRow>[] = [];

    if (enableSelection) {
      const hasDisabled = !!disabledRows && disabledRows.size > 0;

      if (hasDisabled) {
        // Custom selection column: locks disabled rows visually and in interaction.
        // eslint-disable-next-line react-hooks/refs -- refs are read inside column callbacks (not during render)
        baseCols.push({
          key: 'select-row',
          name: '',
          width: 50,
          frozen: true,
          renderHeaderCell: () => {
            const current = filteredRowsRef.current;
            const selected = selectedRowsRef.current;
            const disabled = disabledRowsRef.current;
            const selectable = current.filter(r => !disabled?.has(r.id as string | number));
            const allSelected = selectable.length > 0 &&
              selectable.every(r => selected?.has(r.id as string | number));
            const someSelected = !allSelected &&
              selectable.some(r => selected?.has(r.id as string | number));

            return (
              <div className="flex items-center justify-center h-full">
                <input
                  type="checkbox"
                  checked={allSelected}
                  ref={el => { if (el) el.indeterminate = someSelected; }}
                  onChange={e => {
                    const handler = onSelectedRowsChangeRef.current;
                    if (!handler) return;
                    const newSet = new Set(selectedRowsRef.current ?? []);
                    selectable.forEach(r => {
                      const id = r.id as string | number;
                      if (e.target.checked) newSet.add(id);
                      else newSet.delete(id);
                    });
                    handler(newSet);
                  }}
                  className="cursor-pointer"
                />
              </div>
            );
          },
          renderCell: ({ row }: { row: GridRow }) => {
            const id = row.id as string | number;
            const isDisabled = disabledRowsRef.current?.has(id) ?? false;
            const isSelected = selectedRowsRef.current?.has(id) ?? false;

            const tooltip = isDisabled
              ? isSelected
                ? 'Administrators always hold this permission via structural lock. It cannot be revoked.'
                : 'Structurally locked to Administrators — granting this to role has no effect.'
              : undefined;

            return (
              <div className="flex items-center justify-center h-full">
                <input
                  type="checkbox"
                  checked={isSelected}
                  disabled={isDisabled}
                  title={tooltip}
                  onChange={() => {
                    if (isDisabled) return;
                    const handler = onSelectedRowsChangeRef.current;
                    if (!handler) return;
                    const newSet = new Set(selectedRowsRef.current ?? []);
                    if (isSelected) newSet.delete(id);
                    else newSet.add(id);
                    handler(newSet);
                  }}
                  className={isDisabled ? 'opacity-40 cursor-not-allowed' : 'cursor-pointer'}
                />
              </div>
            );
          }
        });
      } else {
        baseCols.push({ ...SelectColumn, width: 50, frozen: true });
      }
    }

    if (customColumns) {
      return [...baseCols, ...customColumns];
    }

    if (rows.length === 0) return baseCols;

    const autoCols = Object.keys(rows[0])
      .filter(key => key !== 'id' && key !== '_id' && typeof rows[0][key] !== 'object')
      .map(key => ({
        key,
        name: key.charAt(0).toUpperCase() + key.slice(1).replace(/([A-Z])/g, ' $1'),
        resizable: true,
      }));

    return [...baseCols, ...autoCols];
  }, [rows, enableSelection, customColumns, disabledRows]);

  // Guard: prevent disabled rows from being toggled even if called externally.
  const handleSelectedRowsChange = (newSelection: Set<string | number>) => {
    if (!onSelectedRowsChange) return;
    if (!disabledRows || disabledRows.size === 0) {
      onSelectedRowsChange(newSelection);
      return;
    }
    // Re-apply the current state of disabled rows regardless of what was passed.
    disabledRows.forEach(id => {
      if (selectedRows?.has(id)) newSelection.add(id);
      else newSelection.delete(id);
    });
    onSelectedRowsChange(newSelection);
  };

  return (
    <div className="w-full border border-border rounded-lg bg-card shadow-sm flex flex-col overflow-hidden">

      <div className="p-4 border-b border-border flex flex-col sm:flex-row justify-between items-center bg-muted/30 gap-4">
        <h2 className="font-bold text-foreground">{title}</h2>
        <input
          type="text"
          placeholder="Search items..."
          className="border border-border rounded-md px-3 py-1.5 text-sm outline-none focus:border-primary bg-background text-foreground placeholder:text-muted-foreground"
          onChange={(e) => setSearchQuery(e.target.value)}
        />
      </div>

      <div className="flex-1 min-h-100">
        {isLoading ? (
          <div className="h-full flex items-center justify-center text-muted-foreground text-sm py-20">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mr-3"></div>
            Loading {title}...
          </div>
        ) : (
          <DataGrid
            columns={columns}
            rows={filteredRows}
            rowKeyGetter={(r) => r.id as string | number}
            selectedRows={selectedRows}
            onSelectedRowsChange={handleSelectedRowsChange}
            className="h-full min-h-100"
          />
        )}
      </div>

      {endpoint && (
        <div className="p-3 border-t border-border flex justify-between items-center bg-muted/30">
          <div className="text-sm text-foreground">
            Page <strong>{page}</strong> of <strong>{paginationInfo.totalPages}</strong>
            <span className="ml-2 text-muted-foreground">(Total: {paginationInfo.totalCount})</span>
          </div>

          <div className="flex gap-2">
            <button
              disabled={!paginationInfo.hasPreviousPage || isLoading}
              onClick={() => setPage(prev => prev - 1)}
              className="px-4 py-1.5 border border-border rounded-md text-sm bg-card hover:bg-muted/50 disabled:opacity-50 transition-colors"
            >
              Previous
            </button>
            <button
              disabled={!paginationInfo.hasNextPage || isLoading}
              onClick={() => setPage(prev => prev + 1)}
              className="px-4 py-1.5 border border-border rounded-md text-sm bg-card hover:bg-muted/50 disabled:opacity-50 transition-colors"
            >
              Next
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
